                ImGui::Separator();
                ImGui::Text("Wall Frames");
                ImGui::SliderInt("Frame Width##fw", &m_frameSizeSetting, 1, 16, "%dm");
                ImGui::SliderInt("Frame Height##fh", &m_frameHeightSetting, 1, 16, "%dm");
